class FfiConverterTypeAsyncContext: FfiConverter<AsyncContext, ulong> {
    public static FfiConverterTypeAsyncContext INSTANCE = new FfiConverterTypeAsyncContext();


    public override ulong Lower(AsyncContext value) {
        return value.CallWithPointer(thisPtr => thisPtr);
    }

    public override AsyncContext Lift(ulong value) {
        return new AsyncContext(value);
    }

    public override AsyncContext Read(BigEndianStream stream) {
        return Lift(stream.ReadULong());
    }

    public override int AllocationSize(AsyncContext value) {
        return 8;
    }

    public override void Write(AsyncContext value, BigEndianStream stream) {
        stream.WriteULong(Lower(value));
    }
}



