            return rustObj.CallWithPointer(thisPtr => thisPtr);
        } else {
            // C# object, generate a new handle map entry and return it.
            return handleMap.Insert(value);
        }
    }

    public override ContextNotifier Lift(ulong value) {
        if ((value & 1UL) == 0UL) {
